html:
{% set company_doc = frappe.get_doc('Company', doc.company) %}
<!DOCTYPE html>
<html>
<head>
<meta charset="utf-8">
<style>
  body{font-family:Arial,sans-serif;font-size:12px;color:#1a1a1a;margin:0;padding:0}
  .wrap{max-width:820px;margin:0 auto;padding:28px}
  .hdr{display:flex;justify-content:space-between;align-items:flex-start;border-bottom:2px solid #1a3a6b;padding-bottom:14px;margin-bottom:18px}
  .logo img{max-height:56px}
  .co{text-align:right}
  .co h3{margin:0;font-size:14px;color:#1a3a6b}
  .co p{margin:2px 0;font-size:10px;color:#555}
  .title-bar{display:flex;justify-content:space-between;align-items:center;background:#1a3a6b;color:#fff;padding:10px 16px;border-radius:4px;margin-bottom:16px}
  .title-bar h2{margin:0;font-size:16px;letter-spacing:1px;text-transform:uppercase}
  .title-bar .ref{font-size:11px;opacity:.85}
  .meta-strip{display:flex;gap:0;margin-bottom:16px;border:1px solid #dce4f0;border-radius:4px;overflow:hidden}
  .meta-cell{flex:1;padding:10px 14px;border-right:1px solid #dce4f0}
  .meta-cell:last-child{border-right:none}
  .meta-cell label{font-size:9px;font-weight:700;text-transform:uppercase;color:#888;display:block;margin-bottom:2px}
  .meta-cell span{font-size:12px;font-weight:600;color:#1a1a1a}
  .two-col{display:flex;gap:20px;margin-bottom:16px}
  .box{flex:1;border:1px solid #dce4f0;border-radius:4px;padding:12px 14px}
  .box h4{margin:0 0 8px;font-size:10px;font-weight:700;text-transform:uppercase;color:#1a3a6b;letter-spacing:.5px;border-bottom:1px solid #eef1f6;padding-bottom:4px}
  .frow{margin-bottom:5px;display:flex}
  .frow label{font-size:9px;font-weight:700;text-transform:uppercase;color:#888;width:110px;flex-shrink:0}
  .frow span{font-size:11px;color:#1a1a1a}
  table.items{width:100%;border-collapse:collapse;margin-bottom:16px}
  table.items th{background:#1a3a6b;color:#fff;padding:8px 10px;font-size:10px;text-align:left}
  table.items td{padding:8px 10px;font-size:11px;border-bottom:1px solid #eef1f6;vertical-align:top}
  table.items tr:last-child td{border-bottom:none}
  table.items .sno{width:30px;text-align:center}
  .instr{background:#fffbeb;border-left:3px solid #f59e0b;padding:10px 14px;font-size:11px;color:#78350f;border-radius:0 4px 4px 0;margin-bottom:16px}
  .sig-row{display:flex;gap:30px;margin-top:28px}
  .sig-box{flex:1;border-top:1px solid #333;padding-top:8px}
  .sig-box p{margin:2px 0;font-size:10px;color:#555}
  .badge{display:inline-block;padding:2px 8px;border-radius:10px;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px}
  .badge-blue{background:#dbeafe;color:#1e40af}
  .badge-green{background:#dcfce7;color:#166534}
  .badge-yellow{background:#fef9c3;color:#854d0e}
  .footer{margin-top:20px;padding-top:10px;border-top:1px solid #e2e8f0;font-size:9px;color:#94a3b8;text-align:center}
</style>
</head>
<body>
<div class="wrap">

  <div class="hdr">
    <div class="logo">
      {% if company_doc.company_logo %}<img src="{{ company_doc.company_logo }}">{% else %}<h3 style="color:#1a3a6b;margin:0">{{ doc.company }}</h3>{% endif %}
    </div>
    <div class="co">
      <h3>{{ doc.company }}</h3>
      {% if company_doc.address %}<p>{{ company_doc.address }}</p>{% endif %}
      {% if company_doc.phone_no %}<p>Tel: {{ company_doc.phone_no }}</p>{% endif %}
      {% if company_doc.email %}<p>{{ company_doc.email }}</p>{% endif %}
    </div>
  </div>

  <div class="title-bar">
    <h2>Material Dispatch Note</h2>
    <div class="ref">Ref: {{ doc.name }} &nbsp;|&nbsp; Date: {{ frappe.format(doc.dispatch_date, 'Date') }}</div>
  </div>

  <div class="meta-strip">
    <div class="meta-cell"><label>Dispatch Type</label><span>{{ doc.dispatch_type }}</span></div>
    <div class="meta-cell"><label>Status</label><span>{{ doc.status }}</span></div>
    <div class="meta-cell"><label>Salesperson</label><span>{{ doc.requested_salesperson or '—' }}</span></div>
    {% if doc.sales_order %}<div class="meta-cell"><label>Sales Order</label><span>{{ doc.sales_order }}</span></div>{% endif %}
    {% if doc.gate_pass_number %}<div class="meta-cell"><label>Gate Pass / LPO</label><span>{{ doc.gate_pass_number }}</span></div>{% endif %}
  </div>

  <div class="two-col">
    <div class="box">
      <h4>Recipient</h4>
      <div class="frow"><label>Customer</label><span><b>{{ doc.customer }}</b></span></div>
      <div class="frow"><label>Contact</label><span>{{ doc.contact_person or '—' }}</span></div>
      <div class="frow"><label>Mobile</label><span>{{ doc.mobile or '—' }}</span></div>
      <div class="frow"><label>Country</label><span>{{ doc.country or '—' }}</span></div>
      <div class="frow"><label>Address</label><span>{{ doc.delivery_address or '—' }}</span></div>
      <div class="frow"><label>Expected Delivery</label><span>{% if doc.expected_delivery_date %}{{ frappe.format(doc.expected_delivery_date,'Date') }}{% else %}—{% endif %}</span></div>
    </div>
    <div class="box">
      <h4>Vehicle & Driver</h4>
      <div class="frow"><label>Vehicle / Plate</label><span><b>{{ doc.vehicle_number or '—' }}</b></span></div>
      <div class="frow"><label>Driver</label><span>{{ doc.driver_name or '—' }}</span></div>
      <div class="frow"><label>Driver Mobile</label><span>{{ doc.driver_mobile or '—' }}</span></div>
      <div class="frow"><label>Transport Co.</label><span>{{ doc.transport_company or '—' }}</span></div>
    </div>
  </div>

  <table class="items">
    <thead>
      <tr>
        <th class="sno">#</th>
        <th>Item</th>
        <th>Description</th>
        <th style="width:60px;text-align:right">Qty</th>
        <th style="width:60px">UOM</th>
        <th>Serial No(s)</th>
        <th>Demo Asset</th>
        <th>Remarks</th>
      </tr>
    </thead>
    <tbody>
      {% for item in doc.items %}
      <tr>
        <td class="sno">{{ loop.index }}</td>
        <td><b>{{ item.item_code }}</b><br><span style="font-size:10px;color:#64748b">{{ item.item_name or '' }}</span></td>
        <td>{{ item.description or '—' }}</td>
        <td style="text-align:right"><b>{{ item.qty }}</b></td>
        <td>{{ item.uom or '—' }}</td>
        <td style="font-size:10px">{{ item.serial_no or '—' }}</td>
        <td style="font-size:10px">{{ item.demo_asset or '—' }}</td>
        <td style="font-size:10px">{{ item.remarks or '' }}</td>
      </tr>
      {% endfor %}
    </tbody>
  </table>

  {% if doc.special_instructions %}
  <div class="instr"><b>Special Instructions:</b> {{ doc.special_instructions }}</div>
  {% endif %}

  <div class="sig-row">
    <div class="sig-box">
      <p><b>Dispatched By ({{ doc.company }})</b></p>
      <p>Name: ______________________________</p>
      <p>Signature: __________________________</p>
      <p>Date: {{ frappe.format(doc.dispatch_date, 'Date') }}</p>
    </div>
    <div class="sig-box">
      <p><b>Received By ({{ doc.customer }})</b></p>
      <p>Name: {{ doc.receiver_name or '______________________________' }}</p>
      <p>Designation: {{ doc.receiver_designation or '___________________' }}</p>
      <p>Signature &amp; Stamp: ________________</p>
      <p>Date: {{ frappe.format(doc.received_date, 'Date') if doc.received_date else '______________________________' }}</p>
    </div>
    <div class="sig-box">
      <p><b>Driver / Carrier</b></p>
      <p>Name: {{ doc.driver_name or '______________________________' }}</p>
      <p>Vehicle: {{ doc.vehicle_number or '______________________________' }}</p>
      <p>Signature: __________________________</p>
    </div>
  </div>

  <div class="footer">This is a computer-generated document. No financial values are disclosed herein. &nbsp;|&nbsp; {{ doc.company }} &nbsp;|&nbsp; {{ doc.name }}</div>

</div>
</body>
</html>
